/**
 * scripts/generate-resume-context.js
 *
 * Reads src/data/resume.json (already generated by yaml-to-json.js)
 * and writes worker/src/resume-context.js — a plain-text context string
 * embedded in the Cloudflare Worker as a constant.
 *
 * Run order in package.json build:
 *   yaml-to-json → generate-resume-context → copy-assets → vite build
 */

import fs from 'fs'
import path from 'path'
import { fileURLToPath } from 'url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const root      = path.resolve(__dirname, '..')

const resume = JSON.parse(
  fs.readFileSync(path.join(root, 'src', 'data', 'resume.json'), 'utf8')
)

const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec']
function fmtDate(d) {
  if (d === 'present') return 'Present'
  const [y, m] = d.split('-')
  return `${MONTHS[parseInt(m, 10) - 1]} ${y}`
}

const lines = []

// ── Profile ───────────────────────────────────────────────────────────────────
lines.push(`NAME: ${resume.profile.name}`)
lines.push(`TITLE: ${resume.profile.title}`)
lines.push(`LOCATION: ${resume.profile.location}`)
lines.push(`SUMMARY: ${resume.profile.summary}`)
lines.push('')

// ── Contact ───────────────────────────────────────────────────────────────────
lines.push('CONTACT:')
lines.push(`  Email: ${resume.contact.email}`)
lines.push(`  Phone: ${resume.contact.phone}`)
lines.push(`  LinkedIn: ${resume.contact.linkedin}`)
lines.push(`  GitHub: ${resume.contact.github}`)
lines.push('')

// ── Experience ────────────────────────────────────────────────────────────────
lines.push('EXPERIENCE:')
for (const entry of resume.experience) {
  const positions = entry.positions || [{ role: entry.role, start: entry.start, end: entry.end, highlights: entry.highlights || [] }]
  const starts = positions.map(p => p.start).sort()
  const ends   = positions.map(p => p.end)
  const overall = `${fmtDate(starts[0])} – ${ends.includes('present') ? 'Present' : fmtDate(ends.sort().at(-1))}`
  lines.push(`  ${entry.company} (${overall})`)
  for (const pos of positions) {
    lines.push(`    Role: ${pos.role} (${fmtDate(pos.start)} – ${fmtDate(pos.end)})`)
    for (const h of pos.highlights) lines.push(`    - ${h}`)
  }
}
lines.push('')

// ── Skills ────────────────────────────────────────────────────────────────────
lines.push('SKILLS:')
for (const [cat, items] of Object.entries(resume.skills)) {
  lines.push(`  ${cat}: ${items.join(', ')}`)
}
lines.push('')

// ── Certifications ────────────────────────────────────────────────────────────
lines.push('CERTIFICATIONS:')
for (const cert of resume.certifications) {
  lines.push(`  - ${cert.name}`)
}
lines.push('')

// ── Projects ──────────────────────────────────────────────────────────────────
lines.push('PROJECTS:')
for (const proj of resume.projects) {
  lines.push(`  ${proj.name}: ${proj.description}`)
  if (proj.tags) lines.push(`    Tags: ${proj.tags.join(', ')}`)
}

const context = lines.join('\n')

// Write to worker source directory
const outDir = path.join(root, 'worker', 'src')
if (!fs.existsSync(outDir)) fs.mkdirSync(outDir, { recursive: true })

fs.writeFileSync(
  path.join(outDir, 'resume-context.js'),
  `// AUTO-GENERATED — do not edit. Run: npm run generate-resume-context\nexport const RESUME_CONTEXT = ${JSON.stringify(context)}\n`
)

console.log('✅ resume.json → worker/src/resume-context.js')
